SELECT variant_id, COUNT(comment_id) AS comment_count, MAX(created_at) AS last_comment_time
FROM variant_comments
GROUP BY variant_id;

SELECT variant_id
FROM variant_dataset_links
WHERE dataset_id = 2;

SELECT name
FROM variant_datasets
WHERE dataset_id = 1;

SELECT comment, created_at
FROM variant_comments
ORDER BY created_at ASC;

SELECT variant_id, bp, p
FROM genetic_variants
WHERE p > 0.05;

SELECT snp_name
FROM snps
WHERE snp_id = 1;

SELECT snp_name
FROM snps
WHERE snp_id > 0;

SELECT COUNT(*) AS update_count
FROM variant_history
WHERE change_type = 'update';

SELECT chr_number, length
FROM chromosomes
ORDER BY length DESC;

SELECT changed_by, COUNT(*) AS change_count
FROM variant_history
GROUP BY changed_by;
